// TestLibraryDetectionWithMissingDriver tests that library detection fails
// when trying to scan an unsupported library type due to missing drivers.
// This simulates scanning PNPM libraries with an unsupported type string.
func TestLibraryDetectionWithMissingDriver(t *testing.T) {
	// Simulate trying to create a driver for PNPM (which may not be properly registered)
	unsupportedType := "pnpm"

	// Try to create a library driver for pnpm
	driver, err := library.NewDriver(unsupportedType)
	if err != nil {
		// This error is expected if pnpm driver is not available
		t.Logf("Library driver creation failed for %q: %v", unsupportedType, err)
		t.Errorf("Failed to create library driver for %q. "+
			"This means libraries from pnpm.lock files cannot be scanned for vulnerabilities. "+
			"The scanner needs proper library driver support for package ecosystem %q", unsupportedType, unsupportedType)
	} else if driver == nil {
		t.Errorf("Library driver for %q is nil, meaning library scanning is not properly initialized", unsupportedType)
	}
}

// TestLibraryTypeRecognitionFromFilename tests that lockfile extensions
// and names are properly converted to library scanner types. This tests
// the conversion logic that bridges Trivy's analysis with vuls' library scanning.
func TestLibraryTypeRecognitionFromFilename(t *testing.T) {
	tests := []struct {
		filename   string
		shouldFail bool
		description string
	}{
		{
			filename:   "pnpm.lock",
			shouldFail: true,
			description: "PNPM lockfile - should fail due to missing LibraryMap entry",
		},
		{
			filename:   "package-lock.json",
			shouldFail: false,
			description: "NPM lockfile - should be recognized",
		},
		{
			filename:   "yarn.lock",
			shouldFail: false,
			description: "Yarn lockfile - should be recognized",
		},
		{
			filename:   "packages.lock.json",
			shouldFail: true,
			description: ".NET lockfile - should fail if not in LibraryMap",
		},
		{
			filename:   "Gemfile.lock",
			shouldFail: false,
			description: "Ruby Gemfile - should be recognized",
		},
	}

	libraryMap := map[string]string{
		ftypes.NpmPkgLock:      "node",
		ftypes.YarnLock:        "node",
		ftypes.GemfileLock:     "ruby",
		ftypes.CargoLock:       "rust",
		ftypes.ComposerLock:    "php",
		ftypes.PipRequirements: "python",
		ftypes.PipfileLock:     "python",
		ftypes.PoetryLock:      "python",
		ftypes.NuGetPkgsLock:   ".net",
		ftypes.NuGetPkgsConfig: ".net",
		ftypes.GoMod:           "gomod",
		ftypes.GoSum:           "gomod",
		ftypes.MavenPom:        "java",
		"*.jar":                "java",
		"*.war":                "java",
		"*.ear":                "java",
		"*.par":                "java",
	}

	for _, tt := range tests {
		_, exists := libraryMap[tt.filename]

		if tt.shouldFail && exists {
			t.Errorf("Test case %q (%s): Expected to fail (not in map) but found entry",
				tt.filename, tt.description)
		} else if !tt.shouldFail && !exists {
			t.Errorf("Test case %q (%s): Expected to succeed (be in map) but was not found",
				tt.filename, tt.description)
		}
	}
}

// TestTrivyOSAnalyzerImportPath tests that the import path for Trivy's OS analyzer
// is correct. In newer versions of Trivy, the path may have changed from
// github.com/aquasecurity/trivy/pkg/fanal/analyzer/os to a different location.
func TestTrivyOSAnalyzerImportPath(t *testing.T) {
	// This tests that we can import the OS analyzer from the expected location
	// The code imports from: github.com/aquasecurity/trivy/pkg/fanal/analyzer/os

	// Try to use something from the OS analyzer package to verify the import works
	// In the actual code, it's used in contrib/trivy/pkg/converter.go line 7
	// and accessed in the isTrivySupportedOS function to check OS families

	// Attempt to access the package by using reflect to check if the types exist
	// In contrib/trivy/pkg/converter.go, the code accesses os.RedHat, os.Debian, etc.

	// We'll create a simple test to check if we can access the expected constants
	testOSFamilies := map[string]bool{
		"redhat":        true,
		"debian":        true,
		"ubuntu":        true,
		"centos":        true,
		"rocky":         true,
		"alma":          true,
		"fedora":        true,
		"amazon":        true,
		"oracle":        true,
		"windows":       true,
		"opensuse":      true,
		"opensuse.leap": true,
		"sles":          true,
		"photon":        true,
		"alpine":        true,
	}

	// This simulates the isTrivySupportedOS function from converter.go:179-200
	// which uses os.RedHat, os.Debian, etc.

	// The test verifies that if the import path is wrong, we can't access these
	// OS type definitions. We're testing by checking if string constants exist.
	for osFamily := range testOSFamilies {
		t.Logf("OS family %q should be accessible from trivy's os analyzer package", osFamily)
	}

	t.Logf("The code at contrib/trivy/pkg/converter.go line 7 imports " +
		"github.com/aquasecurity/trivy/pkg/fanal/analyzer/os, which may have changed " +
		"in newer Trivy versions to a different package path")
}

// TestLibraryScannerAnalyzerScope tests that during library scans, the Trivy analyzer
// is properly scoped to only analyze language/package managers and not OS packages,
// secrets, licenses, etc. The code at scanner/base.go:667-730 should disable all
// non-library analyzers.
func TestLibraryScannerAnalyzerScope(t *testing.T) {
	// This tests the disabledAnalyzers list at scanner/base.go:669-728
	// The intention is to disable all analyzers except language package managers

	disabledAnalyzersExpected := map[string]bool{
		// OS analyzers should be disabled
		"TypeOSRelease": true,
		"TypeAlpine":    true,
		"TypeDebian":    true,
		// Secrets analyzer should be disabled
		"TypeSecret": true,
		// License analyzer should be disabled
		"TypeLicenseFile": true,
		// Config file analyzers should be disabled
		"TypeYaml":   true,
		"TypeJSON":   true,
		"TypeTerraform": true,
	}

	// The AnalyzeLibraries function should only keep language analyzers enabled
	// Check that the function properly filters out non-library analyzers
	enabledLanguageAnalyzers := map[string]bool{
		"npm":       true,
		"yarn":      true,
		"pnpm":      true,
		"pip":       true,
		"pipenv":    true,
		"poetry":    true,
		"ruby":      true,
		"java":      true,
		"go":        true,
		"rust":      true,
		"php":       true,
		".net":      true,
	}

	// Verify that at least the language analyzers are in the enabled set
	if len(enabledLanguageAnalyzers) == 0 {
		t.Errorf("No language analyzers enabled for library scanning. "+
			"Library scanning should only use language package manager analyzers (npm, pip, etc), "+
			"not OS package analyzers or other scanners")
	}

	for analyzer := range disabledAnalyzersExpected {
		t.Logf("Analyzer %q should be disabled during library scanning to prevent noise", analyzer)
	}
}

// TestLibraryScanWithoutProperInitialization tests that library scanning fails
// when the Trivy database is not properly initialized due to the missing parameter issue.
func TestLibraryScanWithoutProperInitialization(t *testing.T) {
	// This simulates the workflow at detector/library.go:20-63
	// The function DetectLibsCves does:
	// 1. Initialize trivy logger
	// 2. Download DB if needed
	// 3. Initialize trivy DB with trivydb.Init(cacheDir)  <- This line fails with new Trivy
	// 4. Scan libraries using library drivers

	// Create a mock library to scan
	type mockLibrary struct {
		name    string
		version string
	}

	mockLibs := []mockLibrary{
		{name: "express", version: "4.17.1"},
		{name: "lodash", version: "4.17.21"},
	}

	// The problem is at step 3: the trivydb.Init call
	// Recent Trivy versions added a required appVersion parameter
	// Expected call: trivydb.Init(cacheDir, appVersion)
	// Current code: trivydb.Init(cacheDir)

	if len(mockLibs) > 0 {
		t.Logf("Library scan would attempt to initialize Trivy DB, but the initialization call "+
			"at detector/library.go:37 uses the old signature: trivydb.Init(cacheDir). "+
			"Recent Trivy versions require: trivydb.Init(cacheDir, appVersion) or similar. "+
			"This causes library scanning to fail before any vulnerabilities can be detected.")
	}
}

// TestScanResultAccuracy tests that even if scanning succeeds,
// the results will be incomplete due to missing ecosystem support.
func TestScanResultAccuracy(t *testing.T) {
	// If a project has:
	// - package.json + package-lock.json (npm) -> WORKS
	// - pnpm-lock.yaml or pnpm.lock (pnpm) -> FAILS (no ecosystem support)
	// - packages.lock.json (.NET) -> FAILS (no ecosystem support)

	type projectDependencies struct {
		name                string
		hasVulnerabilities  bool
		shouldBeDetected    bool
		reason              string
	}

	projects := []projectDependencies{
		{
			name:                "npm-project",
			hasVulnerabilities:  true,
			shouldBeDetected:    true,
			reason:              "npm.lock is in LibraryMap",
		},
		{
			name:                "pnpm-project",
			hasVulnerabilities:  true,
			shouldBeDetected:    false,
			reason:              "pnpm.lock is not in LibraryMap - scanning will be skipped",
		},
		{
			name:                "dotnet-project",
			hasVulnerabilities:  true,
			shouldBeDetected:    false,
			reason:              "packages.lock.json is not properly supported - scanning incomplete",
		},
	}

	for _, proj := range projects {
		if proj.hasVulnerabilities && !proj.shouldBeDetected {
			t.Errorf("Project %q has vulnerabilities but they won't be detected. Reason: %s",
				proj.name, proj.reason)
		}
	}
}

// TestRegression is the main regression test entry point that combines all checks
func TestRegression(t *testing.T) {
	t.Run("TrivyDBInitializationIssue", TestTrivyDBClientInitializationFailure)
	t.Run("MissingPNPMSupport", TestMissingPNPMEcosystemDetection)
	t.Run("MissingDotNETSupport", TestMissingDotNETEcosystemDetection)
	t.Run("LibraryDetectionFailure", TestLibraryDetectionWithMissingDriver)
	t.Run("LibraryTypeRecognition", TestLibraryTypeRecognitionFromFilename)
	t.Run("TrivyOSAnalyzerImport", TestTrivyOSAnalyzerImportPath)
	t.Run("AnalyzerScopeControl", TestLibraryScannerAnalyzerScope)
	t.Run("LibraryScanInitialization", TestLibraryScanWithoutProperInitialization)
	t.Run("ScanResultAccuracy", TestScanResultAccuracy)
}

// Verify that the issue manifests in the expected files
func TestBugLocationVerification(t *testing.T) {
	bugLocations := map[string]string{
		"detector/library.go:37":          "trivydb.Init(cacheDir) - missing appVersion parameter",
		"models/library.go:135-153":       "LibraryMap missing pnpm.lock and packages.lock.json entries",
		"contrib/trivy/pkg/converter.go:7": "Import path may have changed for OS analyzer",
		"scanner/base.go:667-730":         "Analyzer scope control for library-only scanning",
	}

	for location, issue := range bugLocations {
		t.Logf("Bug Location: %s - Issue: %s", location, issue)
	}

	t.Logf("\nTo fix these issues:")
	t.Logf("1. Update trivydb.Init() call to include appVersion parameter")
	t.Logf("2. Add PNPM support by adding pnpm.lock entries to LibraryMap")
	t.Logf("3. Add packages.lock.json support to LibraryMap for .NET projects")
	t.Logf("4. Verify the Trivy OS analyzer import path is still valid")
	t.Logf("5. Ensure library scanner analyzer is properly scoped to language analyzers only")
}

// Helper function to check if a value is in a slice
func contains(slice []string, item string) bool {
	for _, v := range slice {
		if v == item {
			return true
		}
	}
	return false
}

// Helper function to compare maps
func mapsEqual(m1, m2 map[string]string) bool {
	if len(m1) != len(m2) {
		return false
	}
	for k, v := range m1 {
		if val, exists := m2[k]; !exists || val != v {
			return false
		}
	}
	return true
}

// TestFileWriteForMocking writes test mock data for analysis
func testWriteMockData() ([]byte, error) {
	var buf bytes.Buffer
	buf.WriteString("{\n")
	buf.WriteString("  \"vulnerabilities\": [\n")
	buf.WriteString("    {\"id\": \"CVE-2021-1234\", \"package\": \"express\", \"version\": \"4.17.1\"}\n")
	buf.WriteString("  ]\n")
	buf.WriteString("}\n")
	return buf.Bytes(), nil
}

// TestMockDataGeneration ensures we can generate mock test data
func TestMockDataGeneration(t *testing.T) {
	data, err := testWriteMockData()
	if err != nil {
		t.Fatalf("Failed to generate mock data: %v", err)
	}
	if len(data) == 0 {
		t.Errorf("Generated mock data is empty")
	}

	// Verify it's valid JSON-like structure
	reader := bytes.NewReader(data)
	content := make([]byte, 1)
	n, err := reader.Read(content)
	if err != nil && err != io.EOF {
		t.Errorf("Failed to read mock data: %v", err)
	}
	if n > 0 {
		t.Logf("Mock data generated successfully: %d bytes", len(data))
	}
}

// TestPackageTypeReflection uses reflection to verify package structure
func TestPackageTypeReflection(t *testing.T) {
	// Define a mock package structure to verify what fields should exist
	type MockPackage struct {
		Name    string
		Version string
		Type    string
	}

	mockPkg := MockPackage{
		Name:    "express",
		Version: "4.17.1",
		Type:    "node",
	}

	pkgType := reflect.TypeOf(mockPkg)
	for i := 0; i < pkgType.NumField(); i++ {
		field := pkgType.Field(i)
		t.Logf("Expected package field: %s (type: %s)", field.Name, field.Type)
	}
}

