// TestScanResultAccuracy tests that even if scanning succeeds,
// the results will be incomplete due to missing ecosystem support.
func TestScanResultAccuracy(t *testing.T) {
	// If a project has dependencies from different package managers:
	// - package.json + package-lock.json (npm) -> WORKS
	// - pnpm-lock.yaml or pnpm.lock (pnpm) -> FAILS (no ecosystem support)
	// - packages.lock.json (.NET) -> POTENTIALLY FAILS (support incomplete)
	//
	// Users would see vulnerabilities ONLY for npm packages, missing PNPM packages entirely.

	type projectDependencies struct {
		name               string
		hasVulnerabilities bool
		canBeDetected      bool
		reason             string
	}

	projects := []projectDependencies{
		{
			name:               "npm-project",
			hasVulnerabilities: true,
			canBeDetected:      true,
			reason:             "package-lock.json is in LibraryMap - supported",
		},
		{
			name:               "pnpm-project",
			hasVulnerabilities: true,
			canBeDetected:      false,
			reason:             "pnpm.lock is not in LibraryMap - NOT supported (BUG)",
		},
		{
			name:               "yarn-project",
			hasVulnerabilities: true,
			canBeDetected:      true,
			reason:             "yarn.lock is in LibraryMap - supported",
		},
		{
			name:               "dotnet-project",
			hasVulnerabilities: true,
			canBeDetected:      true,
			reason:             "packages.lock.json is in LibraryMap - supported (but may have driver issues)",
		},
		{
			name:               "mixed-npm-pnpm-project",
			hasVulnerabilities: true,
			canBeDetected:      false,
			reason:             "Only NPM dependencies detected - PNPM dependencies skipped",
		},
	}

	t.Logf("SCAN RESULT ACCURACY ISSUES:")
	t.Logf("")

	buggyProjects := 0
	for _, proj := range projects {
		if proj.hasVulnerabilities && !proj.canBeDetected {
			buggyProjects++
			t.Errorf("Project %q: Has vulnerabilities but they WON'T be detected. Reason: %s",
				proj.name, proj.reason)
		} else if proj.hasVulnerabilities && proj.canBeDetected {
			t.Logf("Project %q: Vulnerabilities WILL be detected. Reason: %s",
				proj.name, proj.reason)
		}
	}

	if buggyProjects > 0 {
		t.Logf("")
		t.Errorf("INCOMPLETE SCANNING: %d out of %d projects cannot have vulnerabilities detected. "+
			"This creates a false sense of security for projects using PNPM and other unsupported ecosystems.",
			buggyProjects, len(projects))
	}
}

